import{_ as t,o as p,c as o,a6 as n,fI as r,fJ as i,fK as s,fL as g,fM as e,fN as l,fO as m,fP as c,fQ as h,fR as d,fS as _,fT as f,fU as b,fV as x,fW as P,fX as k,fY as u,fZ as T,f_ as S,f$ as $,g0 as D,g1 as A}from"./chunks/framework.UYVGz2W_.js";const y=JSON.parse('{"title":"制作固有のワークフロー設定","description":"","frontmatter":{},"headers":[],"relativePath":"ja/configure-prod/index.md","filePath":"ja/configure-prod/index.md"}'),B={name:"ja/configure-prod/index.md"};function R(V,a,E,I,N,j){return p(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="制作固有のワークフロー設定" tabindex="-1">制作固有のワークフロー設定 <a class="header-anchor" href="#制作固有のワークフロー設定" aria-label="Permalink to “制作固有のワークフロー設定”">​</a></h1><h2 id="制作固有の設定" tabindex="-1">制作固有の設定 <a class="header-anchor" href="#制作固有の設定" aria-label="Permalink to “制作固有の設定”">​</a></h2><p><strong>ナビゲーションメニュー</strong>から、ドロップダウンメニューで<strong>設定</strong>を選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューの設定"></p><p>最初のタブ、<strong>パラメータ</strong>では、制作の<strong>技術情報</strong>を変更することができます。</p><p>警告 プレビューをアップロードした後に <strong>FPS</strong> または <strong>解像度</strong> を変更しても変更は適用されません。最初のプレビューを再アップロードする必要があります。 :::</p><p><img src="'+i+'" alt="設定パラメータ"></p><p>ここでは、制作物に対して特定のオプションを有効にすることができます。</p><ul><li><p>クライアントコメントを分離する（お互いに表示されない</p></li><li><p>アーティストによるプレビューのダウンロードを許可する</p></li><li><p>新しいプレビューをエンティティのサムネイルとして自動的に設定する</p></li></ul><p>この制作物に対する<strong>最大リテイク数</strong>を指定することもできます。</p><p>::: ヒント <strong>パラメータ</strong>タブで制作物のアバターを変更することもできます。 :::</p><h2 id="タスクのステータス" tabindex="-1">タスクのステータス <a class="header-anchor" href="#タスクのステータス" aria-label="Permalink to “タスクのステータス”">​</a></h2><h3 id="制作物に対する特定のタスクタイプの設定" tabindex="-1">制作物に対する特定のタスクタイプの設定 <a class="header-anchor" href="#制作物に対する特定のタスクタイプの設定" aria-label="Permalink to “制作物に対する特定のタスクタイプの設定”">​</a></h3><p><strong>ナビゲーションメニュー</strong>でドロップダウンメニューから<strong>設定</strong>を選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューの設定"></p><p>デフォルトでは、プロダクションを作成する際に定義した<strong>タスクステータス</strong>が読み込まれます。</p><p>ただし、グローバルライブラリで先に作成されている場合は、プロダクション中に特定のステータスを追加または削除することができます。</p><p><img src="'+s+'" alt="ステータスの新規設定"></p><p><strong>タスクステータス</strong>タブでは、このプロダクションに追加または削除する<strong>ステータス</strong>を選択し、 <strong>追加</strong>ボタンで選択を確定します。</p><p><img src="'+g+'" alt="ステータスの追加設定"></p><h2 id="タスクタイプ" tabindex="-1">タスクタイプ <a class="header-anchor" href="#タスクタイプ" aria-label="Permalink to “タスクタイプ”">​</a></h2><h3 id="プロダクションで特定のタスクタイプを有効にする" tabindex="-1">プロダクションで特定のタスクタイプを有効にする <a class="header-anchor" href="#プロダクションで特定のタスクタイプを有効にする" aria-label="Permalink to “プロダクションで特定のタスクタイプを有効にする”">​</a></h3><p><strong>ナビゲーションメニュー</strong>で、ドロップダウンメニューから<strong>設定</strong>を選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューの設定"></p><p>デフォルトでは、キットは制作を作成する際に選択した<strong>タスクタイプ</strong>を追加します。</p><p><img src="'+e+'" alt="タスクタイプの新規設定"></p><p>ただし、グローバルライブラリで先に作成されている場合は、特定の<strong>タスクタイプ</strong>を追加または削除することができます。</p><p>たとえば、ライブラリ内の別の制作物からタスクワークフローをインポートすることができます。</p><p><img src="'+l+'" alt="タスクタイプの追加設定"></p><p><strong>タスクタイプ</strong>タブでは、この制作物にインポートまたは削除する制作物またはタスクタイプを選択し、 <strong>インポート</strong>ボタンで選択を検証します。</p><p>::: 警告 アセットやショットを作成した後に新しいタスクタイプを作成した場合は、<strong>DELIVERY</strong>（配信）タスクタイプが作成されます。</p><p><img src="'+m+'" alt="タスクタイプの設定（add）"></p><p>グローバルページで<strong>このタスクタイプを追加</strong>する必要があります。</p><p><img src="'+c+'" alt="タスクタイプの追加（global）"></p><p>ポップアップウィンドウが表示されますので、ドロップダウンメニューから新しいタスクタイプを選択してください。</p><p><img src="'+h+'" alt="Add Task Type Global"></p><p><strong>確認</strong>をクリックして検証します。</p><p><img src="'+d+'" alt="Add Task Type example"></p><p>:::</p><h2 id="アセットタイプ" tabindex="-1">アセットタイプ <a class="header-anchor" href="#アセットタイプ" aria-label="Permalink to “アセットタイプ”">​</a></h2><h3 id="プロダクションでの特定のアセットタイプの有効化" tabindex="-1">プロダクションでの特定のアセットタイプの有効化 <a class="header-anchor" href="#プロダクションでの特定のアセットタイプの有効化" aria-label="Permalink to “プロダクションでの特定のアセットタイプの有効化”">​</a></h3><p><strong>ナビゲーションメニュー</strong>で、ドロップダウンメニューから<strong>設定</strong>を選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューの設定"></p><p>デフォルトでは、プロダクションを作成する際に定義した<strong>アセットタイプ</strong>が読み込まれます。</p><p>ただし、グローバルライブラリで先に作成されている場合は、特定のアセットタイプを追加または削除することができます。</p><p><img src="'+_+'" alt="アセットタイプの新規設定"></p><p><strong>アセットタイプ</strong>タブでは、この制作物に追加または削除する<strong>アセットタイプ</strong>を選択し、 <strong>追加</strong>ボタンで選択を確定します。</p><p><img src="'+f+'" alt="アセットの追加設定"></p><h2 id="ステータスオートメーション" tabindex="-1">ステータスオートメーション <a class="header-anchor" href="#ステータスオートメーション" aria-label="Permalink to “ステータスオートメーション”">​</a></h2><h3 id="プロダクションのステータスオートメーションの設定" tabindex="-1">プロダクションのステータスオートメーションの設定 <a class="header-anchor" href="#プロダクションのステータスオートメーションの設定" aria-label="Permalink to “プロダクションのステータスオートメーションの設定”">​</a></h3><p><strong>ナビゲーションメニュー</strong>で、ドロップダウンメニューから<strong>設定</strong>を選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューの設定"></p><p>デフォルトでは、Kitsuはお客様の<strong>ステータスオートメーション</strong>の** グローバルライブラリ<strong>を</strong>プロダクションライブラリ**に読み込みません。</p><p><img src="'+b+'" alt="設定タスクタイプ新規"></p><p>ただし、生産の種類に応じて、特定の<strong>ステータス自動化</strong>のみを使用することができます。</p><p><strong>ステータス自動化</strong>タブで、この生産で使用する自動化を選択し、 <strong>追加</strong>ボタンで選択を検証します。</p><p><img src="'+x+'" alt="設定 タスクタイプの追加"></p><h2 id="プレビュー背景" tabindex="-1">プレビュー背景 <a class="header-anchor" href="#プレビュー背景" aria-label="Permalink to “プレビュー背景”">​</a></h2><h3 id="特定のプレビュー背景をプロダクションに選択" tabindex="-1">特定のプレビュー背景をプロダクションに選択 <a class="header-anchor" href="#特定のプレビュー背景をプロダクションに選択" aria-label="Permalink to “特定のプレビュー背景をプロダクションに選択”">​</a></h3><p><strong>ナビゲーションメニュー</strong>で、ドロップダウンメニューから<strong>設定</strong>を選択します。</p><p><img src="'+r+'" alt="ドロップダウンメニューの設定"></p><p><strong>プレビュー背景</strong>タブでは、この制作物に追加または削除するHDRファイルを選択できます。</p><p><img src="'+P+'" alt="設定ステータス自動化新規"></p><p><strong>追加</strong>ボタンで選択を確定します。</p><p><img src="'+k+'" alt="アセットの追加設定"></p><p>HDR背景を使用して3Dファイルを確認できます。</p><p><img src="'+u+'" alt="背景のプレビュー例"></p><h2 id="アーティストボード" tabindex="-1">アーティストボード <a class="header-anchor" href="#アーティストボード" aria-label="Permalink to “アーティストボード”">​</a></h2><h3 id="アーティストボードのステータス設定" tabindex="-1">アーティストボードのステータス設定 <a class="header-anchor" href="#アーティストボードのステータス設定" aria-label="Permalink to “アーティストボードのステータス設定”">​</a></h3><p><strong>ナビゲーションメニュー</strong>で、ドロップダウンメニューから<strong>設定</strong>を選択します。</p><p><strong>タスクステータス</strong>タブで、<strong>ボード</strong>ビューのステータスを並べ替えることができます。</p><p><img src="'+s+'" alt="ステータスの新規設定"></p><p><img src="'+T+'" alt="ステータスの順序設定"></p><p>設定が完了したら、<strong>Board Status</strong> タブに移動します。</p><p><img src="'+S+'" alt="Board Status order setting"></p><p>ここでは、<strong>Board view</strong> でどのステータスを誰に表示させるかを選択できます</p><p>ステータスを適切に選択しないと、アーティストにとって選択肢が多すぎて負担になる場合があります。</p><p><img src="'+$+'" alt="ボードステータスの悪い例"></p><p>適切な<strong>ステータス</strong>を選択することで、アーティストにとってより使いやすくなります。</p><p><img src="'+D+'" alt="ボードステータスの順序の設定"></p><p><img src="'+A+'" alt="ボードステータスの良い例"></p>',81)])])}const C=t(B,[["render",R]]);export{y as __pageData,C as default};
